substep.action:
Compose the per-gate prompt. Required content:

- Gate name: {{gate}}
- Slice ID (if I-per-slice): {{slice_id}}
- Ticket tags: {{ticket_tags}}
- Bundle directory: {{bundle_dir}}
- Artifact paths per gate:
  - D-review:           design_path
  - P-review:           plan_paths
  - I-per-slice:        plan_path + commit_sha + worktree_path
  - final-integration:  plan_paths + worktree_path
  - PR-review:          plan_paths + commit_sha + worktree_path

invoke-agent.prompt:
Verify {{gate}} gate for codesmith implementation.

Gate: {{gate}}
{{if I-per-slice: Slice: {{slice_id}}; Commit: {{commit_sha}}}}
{{if I-per-slice or final-integration: Worktree: {{worktree_path}}}}

Artifacts to read:
{{artifact_paths_per_gate}}

Ticket tags: {{ticket_tags}}

Bundle directory: {{bundle_dir}}
